class Solution:
    def getMinSwaps(self, num: str, k: int) -> int:
        num_list = list(num)
        n = len(num_list)

        # Find the k-th smallest wonderful number
        kth_num = num_list[:]
        for _ in range(k):
            # Find the first digit that can be swapped to get a larger number
            for i in range(n - 2, -1, -1):
                if kth_num[i] < max(kth_num[i + 1:]):
                    break
            else:
                break

            # Find the smallest digit greater than kth_num[i] on its right
            for j in range(n - 1, i, -1):
                if kth_num[j] > kth_num[i]:
                    kth_num[i], kth_num[j] = kth_num[j], kth_num[i]
                    break

            # Sort the digits on the right of i in ascending order
            kth_num[i + 1:] = sorted(kth_num[i + 1:])

        # Calculate the minimum number of swaps to get the k-th smallest wonderful number
        num_list = list(num)
        swaps = 0
        for i in range(n):
            if num_list[i] != kth_num[i]:
                j = i + 1
                while num_list[j] != kth_num[i]:
                    j += 1
                while j > i:
                    num_list[j], num_list[j - 1] = num_list[j - 1], num_list[j]
                    swaps += 1
                    j -= 1

        return swaps
